import{_ as t,o as e,c as d,ag as a}from"./chunks/framework.D9bIGSBm.js";const n="/docs/images/what-is-loongcode_1.png",p=JSON.parse('{"title":"LoongCode 是什么","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-loongcode.md","filePath":"guide/what-is-loongcode.md"}'),r={name:"guide/what-is-loongcode.md"};function i(s,o,l,g,c,C){return e(),d("div",null,[...o[0]||(o[0]=[a('<h1 id="loongcode-是什么" tabindex="-1">LoongCode 是什么 <a class="header-anchor" href="#loongcode-是什么" aria-label="Permalink to &quot;LoongCode 是什么&quot;">​</a></h1><p>LoongCode 是一款<strong>桌面 Agent IDE</strong>（集成开发环境）：它把原本只能在命令行中使用的 AI 编程助手（如 Claude Code CLI、OpenAI Codex CLI 等，后续将持续接入更多）装进一个现代化的图形界面，让你不必学习终端命令，就能用对话的方式让 AI 帮你写代码、改文件、跑命令。</p><p><img src="'+n+'" alt="截图：LoongCode 主界面全景，一个任务正在运行中，展示左侧任务栏、中央对话区与右侧工具面板，突出整体布局与各区域边界"></p><h2 id="它是如何工作的" tabindex="-1">它是如何工作的 <a class="header-anchor" href="#它是如何工作的" aria-label="Permalink to &quot;它是如何工作的&quot;">​</a></h2><p>LoongCode 基于 Tauri 2 + React 19 构建，<strong>本身不直接调用任何模型 API</strong>。它的工作方式是：在你每次发起对话时，LoongCode 在后台以子进程方式拉起本机已安装的 <code>claude</code> 或 <code>codex</code> 命令行工具，通过流式 JSON 协议与它们通信，再把实时返回的事件流渲染成你看到的对话与工具调用界面。</p><p>这意味着：</p><ul><li>你的 API 密钥和模型配置由 CLI 工具自己管理，LoongCode 不经手。</li><li>CLI 工具的版本升级（如 Anthropic 发布新版 Claude Code）不需要重装 LoongCode，两者相互独立。</li></ul><h2 id="能用它做什么" tabindex="-1">能用它做什么 <a class="header-anchor" href="#能用它做什么" aria-label="Permalink to &quot;能用它做什么&quot;">​</a></h2><p><strong>多任务并行对话</strong>：每个「任务」对应一个独立的 AI 会话，你可以同时开启多个任务，它们在后台并行运行互不干扰。左侧任务栏实时显示每个任务的状态（空闲、运行中、成功、出错、提问中）。</p><p><strong>工作区与文件管理</strong>：内置文件树、文件查看面板与 Markdown 预览，可直接在 LoongCode 中浏览和管理项目文件；通过 <code>@</code> 提及语法可以在对话中快速引用任意文件。</p><p><strong>Git 集成</strong>：标题栏内置提交（commit）菜单与 Git 审查面板，支持分支切换、查看代码变更（diff）、查看未推送提交数量，无需切换到其他工具。</p><p><strong>多 CLI 支持（Claude / Codex）</strong>：从 v0.7.0 起，LoongCode 已支持 Claude Code CLI 与 OpenAI Codex CLI，并将持续接入更多。你可以为每个任务单独选择使用哪个 CLI，各 CLI 的模型配置各自独立、互不影响。</p><p><strong>可扩展能力（MCP / 插件 / 技能 / 子智能体）</strong>：通过设置页面可以管理 MCP 服务器（为 AI 提供额外工具能力）、插件、技能（自定义斜杠命令）和子智能体，灵活扩展 AI 的能力边界。</p><p><strong>移动端伴侣</strong>：可通过官方 <strong>LoongCode App</strong> 经中转服务远程驱动电脑上的任务，支持实时事件流、历史回放、富输入（斜杠命令 / @文件 / 图片）与任务配置同步，全程端到端加密（见<a href="/docs/settings/mobile-pairing.html">移动端配对</a>）；也可通过<strong>微信 / 飞书机器人</strong>接入纯文本交互，方便在手机上查看进度或发送指令。</p><h2 id="与-claude-code-codex-的关系" tabindex="-1">与 Claude Code / Codex 的关系 <a class="header-anchor" href="#与-claude-code-codex-的关系" aria-label="Permalink to &quot;与 Claude Code / Codex 的关系&quot;">​</a></h2><p>可以这样理解：<strong>CLI 是引擎，LoongCode 是驾驶舱</strong>。</p><ul><li><strong>Claude Code CLI</strong>（由 Anthropic 提供）和 <strong>Codex CLI</strong>（由 OpenAI 提供）负责真正的模型调用、代码执行和文件操作——这是「引擎」。</li><li><strong>LoongCode</strong> 负责把引擎的能力以图形界面的形式呈现出来，提供多任务管理、历史记录、Git 集成等工作流增强——这是「驾驶舱」。</li></ul><p>两者解耦运行：CLI 工具升级新版本后，LoongCode 无需做任何改动；同样，LoongCode 界面的更新也不影响 CLI 的正常工作。</p><h2 id="支持的平台" tabindex="-1">支持的平台 <a class="header-anchor" href="#支持的平台" aria-label="Permalink to &quot;支持的平台&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>架构</th><th>支持情况</th></tr></thead><tbody><tr><td>Windows</td><td>x64</td><td>支持，含自动更新</td></tr><tr><td>Windows</td><td>ARM64</td><td>支持，含自动更新</td></tr><tr><td>macOS</td><td>Intel + Apple Silicon（通用包）</td><td>支持</td></tr><tr><td>Linux</td><td>—</td><td>暂未发布</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解了 LoongCode 是什么之后，前往<a href="/docs/guide/installation.html">安装</a>页面，把它装到你的电脑上。</p>',22)])])}const u=t(r,[["render",i]]);export{p as __pageData,u as default};
